module top_module(
    input A,
    input B,
    input C,
    input D,
    input S0,
    input S1,
    output Y
);wire unused_w1, w2, w3, w4;

    assign unused_w1 = (S1 & S0) ? D : 1'b0;
    assign w2 = (S1 & ~S0) ? C : 1'b0;
    assign w3 = (~S1 & S0) ? B : 1'b0;
    assign w4 = (~S1 & ~S0) ? A : 1'b0;

    assign Y = unused_w1 | w2 | w3 | w4;

endmodule
